+        var lexer = Lexer.init(sql);
+        const first_token = lexer.next();
+        return .{
+            .lexer = lexer,
+            .allocator = allocator,
+            .current = first_token,
+        };
+    }
+
+    /// Parse a SQL string into a SelectStmt.
+    pub fn parse(allocator: std.mem.Allocator, sql: []const u8) ParseError!SelectStmt {
+        var parser = Parser.init(allocator, sql);
